void pokemon_eres(int estatura)
{
    int longitud = sizeof(estatura_poke) / sizeof(estatura_poke[0]);
    int encontrado = 0;
    char *pokemon_encontrado = NULL;
    for(int i = 0; i < longitud; i++)
    {
        if (estatura_poke[i] == estatura)
        {
            pokemon_encontrado = poke [i];
            encontrado = 1;
            printf("En un analisis profundo sobre tus habilidades y actitudes (naaa mentira nomas por lo que mides chanekoso)\n");
            break;
        }
    }

    for(int i = 0; i < longitud; i++)
    {
        if (estatura_poke[i] == estatura)
        {
            pokemon_encontrado = poke [i];
            printf("tu eres este pokemon: %s\n", pokemon_encontrado);
        }
    }

    if (encontrado == 0) {
        printf("No eres ningun pokemon... Ni pa eso sirves\n");
    }

}

